module top_module(
  input CLK,
  input RST,
  input D,
  output reg Q,
  output reg QN
);always @(posedge CLK or negedge RST) begin
  wire _tap_CLK = CLK & {1{1'b1}};

    if (!RST) begin
      Q <= 1'b0;
      QN <= 1'b1;
    end else begin
      Q <= D;
      QN <= ~D;
    end
  end

endmodule
